                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
  using namespace reaction;

  // 1. Create reactive variable
  auto sensor = var(initialValue);

  // 2. Create variables to track recomputation count and last processed value
  int recomputeCount = 0;
  double lastProcessed = initialValue;

  // 3. Create filter-triggered calculation
  auto status = make_signal<std::string>([&] {
    ++recomputeCount;
    lastProcessed = sensor.get();
    return (lastProcessed > levelThreshold) ? std::string("HIGH")
                                            : std::string("NORMAL");
  });

  // Wrap with filter: only propagate when change exceeds diffThreshold
  auto filteredStatus =
      filter(status, [&](const std::string&, const std::string&) {
        double current = sensor.get();
        return std::abs(current - lastProcessed) >= diffThreshold;
      });

  // 4. Apply filter
  // (Filter already applied in construction of filteredStatus)

  // 5. Update sensor with first value
  sensor.set(firstUpdate);
  run();

  // 6. Record recompute count after first update
  int countAfterFirst = recomputeCount;

  // 7. Update sensor with second value
  sensor.set(secondUpdate);
  run();

  // 8. Record recompute count after second update
  int countAfterSecond = recomputeCount;

  // 9. Get final status
  std::string finalStatus = filteredStatus.get();

  // 10. Return final status and counts
  return std::make_tuple(finalStatus, countAfterFirst, countAfterSecond);
}

}  // namespace test_reaction
