    // 2. Initialize stack monitor
    StackMonitor::initialize();

    // 3. Check allocation without monitoring
    snap.smallAllowedWithoutMonitoring = StackMonitor::canAllocate(128);
    snap.largeAllowedWithoutMonitoring = StackMonitor::canAllocate(largeSize);
    snap.runtimeAllowedWithoutMonitoring = StackMonitor::canAllocate(largeSize / 2 + 1);

    // 4. Enable monitoring
