        // consumes almost all remaining capacity.
        snap.allocationBlockedAtLimit = !StackMonitor::canAllocate(1);
    }  // 10. Exit guard scope

    // 11. Check runtime allocation after release
    snap.runtimeAllowedAfterRelease = StackMonitor::canAllocate(largeSize);

    // 12. Return stack allocation snapshot
