    bool deepBeforeShallow;
    bool nullComesFirst;
};

/**
 * Function: Demonstrate ObserverNode::updateDepth cooperating with BatchCompare ordering.
 *
 * @return DepthOrderingSnapshot Comparator outcomes after adjusting node depths.
 */
inline DepthOrderingSnapshot test_observer_depth_ordering() {
    using namespace reaction;

    // 1. Define DepthProbeNode class
    struct DepthProbeNode : core::ObserverNode {
        using core::ObserverNode::ObserverNode;

        void updateDepth(std::size_t depth) {
            core::ObserverNode::updateDepth(depth);
        }

        std::size_t getDepth() const {
            return depth();
        }

        // ObserverNode requires overriding these
        void onInvalidate() override {}
        void onMark() override {}
        void onPropagate() override {}
    };

    // 2. Get thread manager instance
    auto& tm = concurrency::ThreadManager::instance();

    // 3. Reset thread manager state
    tm.reset();

    // 4. Enable thread safety
    tm.enable_thread_safety(true);

    // 5. Create shallow and deep DepthProbeNode instances
    auto shallowNode = std::make_shared<DepthProbeNode>();
    auto deepNode    = std::make_shared<DepthProbeNode>();

    // 6. Create NodeWeak from nodes
    graph::NodeWeak shallowWeak{shallowNode};
    graph::NodeWeak deepWeak{deepNode};

    // 7. Create BatchCompare instance
    graph::BatchCompare comparator;

    DepthOrderingSnapshot snapshot{};

    // 8. Compare initial nodes (same initial depth, ordering by pointer / tie‑breaker)
    snapshot.initialComparatorResult = comparator(shallowWeak, deepWeak);

    // 9. Update depths of nodes: shallow shallower than deep
    shallowNode->updateDepth(1);
    deepNode->updateDepth(2);

    // 10. Compare shallow before deep (shallow should come first)
    snapshot.shallowBeforeDeep = comparator(shallowWeak, deepWeak);

    // 11. Update depth of shallow node again: make it deeper than deep
    shallowNode->updateDepth(3);

    // 12. Compare deep before shallow (deep should now come first)
    snapshot.deepBeforeShallow = comparator(deepWeak, shallowWeak);

    // 13. Create null NodeWeak
    graph::NodeWeak nullWeak;

    // 14. Compare null with shallow
    snapshot.nullComesFirst = comparator(nullWeak, shallowWeak);

    // 15. Return depth ordering snapshot
    return snapshot;
}

}  // namespace test_reaction
