    // 8. Compare initial nodes (same initial depth, ordering by pointer / tie‑breaker)
    snapshot.initialComparatorResult = comparator(shallowWeak, deepWeak);

    // 9. Update depths of nodes: shallow shallower than deep
    shallowNode->updateDepth(1);
    deepNode->updateDepth(2);

    // 10. Compare shallow before deep (shallow should come first)
    snapshot.shallowBeforeDeep = comparator(shallowWeak, deepWeak);

    // 11. Update depth of shallow node again: make it deeper than deep
    shallowNode->updateDepth(3);

    // 12. Compare deep before shallow (deep should now come first)
    snapshot.deepBeforeShallow = comparator(deepWeak, shallowWeak);

    // 13. Create null NodeWeak
    graph::NodeWeak nullWeak;

    // 14. Compare null with shallow
    snapshot.nullComesFirst = comparator(nullWeak, shallowWeak);

    // 15. Return depth ordering snapshot
    return snapshot;
}

